body:
This works with VCS on https://edaplayground.com/ but verilator errors out:

```
%Error-UNSUPPORTED: t/t_interface1_modport.v:35:28: Unsupported: Modport clocking
   35 |    modport  tb (input clk, clocking cb);
      |                            ^~~~~~~~
```

Can you attach an example that shows the issue?  (Must be openly licensed, ideally in test_regress format.)

```
// DESCRIPTION: Verilator: Verilog Test module
//
// This file ONLY is placed under the Creative Commons Public Domain, for
// any use, without warranty, 2013 by Wilson Snyder.
// SPDX-License-Identifier: CC0-1.0

// Very simple test for interface pathclearing

interface ifc;
   integer hidden_from_isub;
   integer value;
   modport out_modport (output value);
endinterface

interface bus_if(input logic clk);

    // Define signals
    logic [31:0] addr;
    logic [31:0] data;
    logic write_enable;
    logic read_enable;
    logic [31:0] read_data;

    // Define a clocking block
    clocking cb @(posedge clk);
        default input #1step output #0;
        input read_data;
        output addr, data, write_enable, read_enable;
    endclocking

    // Define modports for different roles
    modport master (input read_data, output addr, data, write_enable, read_enable);
    modport slave (output read_data, input addr, data, write_enable, read_enable);

   modport  tb (input clk, clocking cb);

endinterface


module t (/*AUTOARG*/
   // Inputs
   clk
   );

   input clk;
   integer cyc=1;

   ifc itop();
   bus_if bus(clk);

   sub  c1 (.isub(itop),
            .i_value(4));

   always @ (posedge clk) begin
      cyc <= cyc + 1;
      if (cyc==20) begin
         if (itop.value != 4) $stop;
         itop.hidden_from_isub = 20;
         if (itop.hidden_from_isub != 20) $stop;
         $write("*-* All Finished *-*\n");
         $finish;
      end
   end
endmodule

module sub
`ifdef NANSI  // bug868
  (
   isub, i_value
   );
   ifc.out_modport isub;   // Note parenthesis are not legal here
   input integer i_value;
`else
  (
   ifc.out_modport isub,
   input integer i_value
   );
`endif

   always @* begin
      isub.value = i_value;
   end
endmodule
```

What 'verilator' command line do we use to run your example?

```
verilator --prefix Vt_interface1_modport_trace ../obj_vlt/t_interface1_modport_trace/Vt_interface1_modport_trace__main.cpp --exe --make gmake --x-assign unique -cc -Mdir obj_vlt/t_interface1_modport_trace --fdedup --debug-check --comp-limit-members 10 --trace --clk clk  -f input.vc +define+TEST_OBJ_DIR=obj_vlt/t_interface1_modport_trace +define+TEST_DUMPFILE=obj_vlt/t_interface1_modport_trace/simx.vcd t/t_interface1_modport.v
```

